{
  "name": "MiCAFE (Michigan's Coordinated Access to Food for the Elderly)",
  "eligibility": {
    "age": 60,
    "income_limits": "Eligibility for underlying benefits like SNAP is based on household composition, monthly income (minus medical expenses in some cases), and countable assets; specific dollar amounts and full household size tables not detailed in sources—refer to SNAP guidelines via MiCAFE assistance[1][2][4]",
    "asset_limits": "Countable assets apply for SER and SNAP eligibility based on household; details on what counts or exemptions not specified[1]",
    "other_requirements": ["Limited income", "Primarily for individuals 60 and older", "Living on limited income to access benefits like SNAP, utilities, medical assistance, prescriptions[1][2]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Application assistance for SNAP (Bridge Card/food benefits), Medicare premiums, Medicare Part D prescription drug benefits, utility assistance, tax programs, medical assistance, and prescriptions; includes phone support, in-home assistance where available, outreach, education, and electronic submission help[1][2][3][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-877-664-2233 (Monday-Friday, 9:00 a.m. to 3:00 p.m.)[1][2][5][8]", "Website: elderlawofmi.org/micafe[2][8]", "In-home or in-person via MiCAFE Network partners where available[3]", "Electronic submission assistance through partners[3]"],
    "processing_time": "Times vary by program (e.g., SNAP); not specified for MiCAFE assistance itself[5]",
    "waitlist": null,
    "forms": ["Assists with SNAP applications and annual recertifications; no specific MiCAFE form name/number listed—uses standard benefit program forms[3]"],
    "documents": ["Not specified; prepare standard proof for SNAP/eligibility (income, assets, household details) as guided during call[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Delivered statewide via MiCAFE Network of partners; in-home assistance availability varies by location[3][7]",
    "offices_or_providers": ["Elder Law of Michigan call center; statewide MiCAFE Network partners for local outreach and assistance[1][3][7][8]"]
  },
  "official_source": "https://www.elderlawofmi.org/micafe[2][8]",
  "gotchas": ["MiCAFE is application assistance, not direct benefits—success depends on underlying program eligibility like SNAP[1][2]", "Nearly 50% of eligible seniors do not enroll in SNAP without help[8]", "Phone hours limited to 9am-3pm M-F[1][2]", "May assist even if not qualifying for Bridge Card (e.g., Medicare help)[2]", "Stigma/barriers addressed via network, but over 160,000 seniors still face hunger[3]"],
  "data_shape_notes": "Advocacy program via statewide network; eligibility tied to variable SNAP/SER rules (household-based income/assets minus medical expenses); no fixed MiCAFE-specific limits or direct benefits provided[1][3][4]"
}
